def ffn_param_count(d_model: int, d_ff: int, n_layers: int, style: str = "gelu") -> dict:
    if style == "swiglu":
        # three matrices: gate, up, down
        per_layer = 3 * d_model * d_ff
    else:
        # two matrices: W1, W2 (ignoring biases)
        per_layer = 2 * d_model * d_ff
    total = per_layer * n_layers
    return {"per_layer": per_layer, "total": total, "total_B": total / 1e9}

# GPT-2 (small)
print(ffn_param_count(768, 3072, 12, "gelu"))
# {'per_layer': 4718592, 'total': 56623104, 'total_B': 0.057}

# LLaMA-2 7B (approx)
print(ffn_param_count(4096, 11008, 32, "swiglu"))
# {'per_layer': 135266304, 'total': 4328521728, 'total_B': 4.329}
# FFN alone accounts for ~62% of the 7B parameter count
